        isWatched(name, _names)
      ) {
        _state.watch = true;
      }
    }
  }
};

const updateTouchAndDirty = (
  name: InternalFieldName,
  fieldValue: unknown,
  isBlurEvent?: boolean,
  shouldDirty?: boolean,
  shouldRender?: boolean,
): Partial<
  Pick<FormState<TFieldValues>, 'dirtyFields' | 'isDirty' | 'touchedFields'>
> => {
  let shouldUpdateField = false;
  let isPreviousDirty = false;
  const output: Partial<FormState<TFieldValues>> & { name: string } = {
    name,
  };

  if (!_options.disabled) {
    if (!isBlurEvent || shouldDirty) {
      const isCurrentFieldPristine = deepEqual(
        get(_defaultValues, name),
        fieldValue,
      );

      if (_proxyFormState.isDirty || _proxySubscribeFormState.isDirty) {
        isPreviousDirty = _formState.isDirty;

        _formState.isDirty = output.isDirty =
          !isCurrentFieldPristine || _getDirty();
        shouldUpdateField = isPreviousDirty !== output.isDirty;
      }

      isPreviousDirty = !!get(_formState.dirtyFields, name);

      if (isCurrentFieldPristine !== _formState.isDirty) {
        _formState.dirtyFields = getDirtyFields(_defaultValues, _formValues);
      } else {
        isCurrentFieldPristine
          ? unset(_formState.dirtyFields, name)
          : set(_formState.dirtyFields, name, true);
      }

      output.dirtyFields = _formState.dirtyFields;
      shouldUpdateField =
        shouldUpdateField ||
        ((_proxyFormState.dirtyFields ||
          _proxySubscribeFormState.dirtyFields) &&
          isPreviousDirty !== !isCurrentFieldPristine);
    }

    if (isBlurEvent) {
      const isPreviousFieldTouched = get(_formState.touchedFields, name);

      if (!isPreviousFieldTouched) {
        set(_formState.touchedFields, name, isBlurEvent);
        output.touchedFields = _formState.touchedFields;
        shouldUpdateField =
          shouldUpdateField ||
          ((_proxyFormState.touchedFields ||
            _proxySubscribeFormState.touchedFields) &&
            isPreviousFieldTouched !== isBlurEvent);
      }
    }

    shouldUpdateField && shouldRender && _subjects.state.next(output);
  }

  return shouldUpdateField ? output : {};
};

const shouldRenderByError = (
  name: InternalFieldName,
  isValid?: boolean,
  error?: FieldError,
  fieldState?: {
    dirty?: FieldNamesMarkedBoolean<TFieldValues>;
    isDirty?: boolean;
    touched?: FieldNamesMarkedBoolean<TFieldValues>;
  },
) => {
  const previousFieldError = get(_formState.errors, name);
  const shouldUpdateValid =
    (_proxyFormState.isValid || _proxySubscribeFormState.isValid) &&
    isBoolean(isValid) &&
    _formState.isValid !== isValid;

  if (_options.delayError && error) {
    delayErrorCallback = debounce(() => updateErrors(name, error));
    delayErrorCallback(_options.delayError);
  } else {
    clearTimeout(timer);
    delayErrorCallback = null;
    error
      ? set(_formState.errors, name, error)
      : unset(_formState.errors, name);
    _formState.errors = { ..._formState.errors };
  }

  if (
    (error ? !deepEqual(previousFieldError, error) : previousFieldError) ||
    !isEmptyObject(fieldState) ||
    shouldUpdateValid
  ) {
    const updatedFormState = {
      ...fieldState,
      ...(shouldUpdateValid && isBoolean(isValid) ? { isValid } : {}),
      errors: _formState.errors,
      name,
    };

    _formState = {
      ..._formState,
      ...updatedFormState,
    };

    _subjects.state.next(updatedFormState);
  }
};

